import{_ as e,o as a,c as r,a4 as o}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"变色效应","description":"","frontmatter":{"title":"变色效应","phenomenon":"color-change"},"headers":[],"relativePath":"zh/optical-phenomena/color-change.md","filePath":"zh/optical-phenomena/color-change.md","lastUpdated":1784177547000}'),d={name:"zh/optical-phenomena/color-change.md"};function n(l,t,h,i,c,p){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="变色效应" tabindex="-1">变色效应 <a class="header-anchor" href="#变色效应" aria-label="Permalink to &quot;变色效应&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>某些宝石在日光（含较多蓝绿光）与白炽灯（含较多红黄光）下呈现 明显不同颜色。最著名的是亚历山大石（变石），日光下绿色，白炽 灯下红色。其他含 Cr³⁺ / V³⁺ 的宝石（蓝宝石、镁铝榴石、尖晶石 变种）也可表现该效应。机制与变石的 Cr³⁺ 双重吸收带有关。</p><h2 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h2><p>Cr³⁺ 离子具有两个主吸收带：一个在黄光区（约 580 nm），一个在 蓝光区（约 425 nm）。当日光（蓝绿富）照射时，黄色透射为主 → 视觉为绿色；当白炽灯（红黄富）照射时，黄光被吸收，蓝色透射 主导，与红色环境光共同呈现红/紫色效果。绿色与红色的对比越强， 变石效应评级越高。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>日光下</th><th>白炽灯下</th></tr></thead><tbody><tr><td>Alexandrite / 亚历山大石</td><td>green / teal</td><td>red / raspberry</td></tr><tr><td>Color-change Sapphire / 变色蓝宝</td><td>blue</td><td>purple</td></tr><tr><td>Color-change Garnet / 变色石榴石</td><td>blue-green</td><td>red-purple</td></tr><tr><td>Color-change Spinel / 变色尖晶石</td><td>blue</td><td>violet</td></tr><tr><td>Color-change Fluorite / 变色萤石</td><td>blue</td><td>purple</td></tr></tbody></table><p><em>详见<a href="./intro.html">光学现象总览</a>。</em></p>',8)])])}const u=e(d,[["render",n]]);export{m as __pageData,u as default};
